<script setup>
import { ref, onMounted, onUnmounted, nextTick } from 'vue';
import { gsap } from 'gsap';

// ref 선언
const serviceMapRef = ref(null);

onMounted(() => {
  nextTick(() => {
    // 1. 애니메이션 대상 선정
    const flowLines = serviceMapRef.value.querySelectorAll('.flow-line');

    if (flowLines.length > 0) {
      // 2. 무한 반복되는 타임라인 생성
      const mapTl = gsap.timeline({
        repeat: -1, // 무한 반복
        defaults: { ease: 'power1.inOut' },
      });

      // 3. 각 선에 애니메이션 적용
      flowLines.forEach((line, index) => {
        // [핵심 해결 방법] DrawSVG 플러그인 없이 구현
        // 해당 path의 전체 길이를 구함
        const length = line.getTotalLength();

        // 초기 세팅: 선을 dasharray로 전체 길이만큼 끊고, offset으로 완전히 숨김
        gsap.set(line, {
          strokeDasharray: length,
          strokeDashoffset: length,
          opacity: 1, // 선은 일단 보이게 함
        });

        // 애니메이션 시퀀스 (순차적)
        // Draw (그리기)
        mapTl
          .to(line, {
            strokeDashoffset: 0,
            duration: 1.5,
            delay: index === 0 ? 1 : 0, // 첫 번째 선은 1초 대기 후 시작
          })
          // Erase (지우기) - 앞 부분이 그려지기 시작할 때 뒷 부분은 지우기 시작 (부드러운 연결)
          .to(
            line,
            {
              strokeDashoffset: -length, // 반대 방향으로 offset을 줘서 지워지게 함
              opacity: 0, // 지워지면서 투명하게
              duration: 1.2,
              ease: 'power2.in',
            },
            '>-0.5',
          ); // 그리기 시작 후 0.5초 뒤에 지우기 시작
      });
    }
  });
});
</script>

<style scoped>
.sb-service-map {
  width: 100%;
  height: auto;
  perspective: 1000px;
}

/* 애니메이션을 적용할 파란색 곡선 스타일 */
.flow-line {
  stroke-width: 2;
  stroke: #3adde9; /* 이미지의 그라데이션 대신 단색으로 하는 것이 깔끔합니다. */
  fill: none;
  /* scrub과 충돌할 수 있으므로 transition은 사용하지 않습니다. */
  will-change: stroke-dashoffset, opacity;
}
</style>
